var e=[{id:`L2_1`,type:`dialog`,speaker:`JAINA_DELTA_NULL_NULL`,text:{KOREA:`아윽……!?`,JPN:`あうっ……！？`,ENG:`Urgh!`,TWN:`唔……！？`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_QM`,text:{KOREA:`물건 확보. 임무 완수. 전군 철수 준비.`,JPN:`ターゲット確保。任務完遂。全軍、撤退準備。`,ENG:`We got what we came for. Mission accomplished. Everyone, withdraw.`,TWN:`東西到手。任務完成，全軍撤退。`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_AVOID`,text:{KOREA:`제이나 양!`,JPN:`ジェイナ！`,ENG:`Jaina!`,TWN:`婕娜！`},stage:{bg:`PROLOGUE_04`,slots:{L:{char_id:`JAKE_DELTA_PLAIN_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_SURPRISE`}}}},{id:`L9_1`,type:`dialog`,speaker:`JAKE_DELTA_PLAIN_NULL`,text:{KOREA:`이런, 리액터를 빼앗겼나?!`,JPN:`くそ、リアクターを奪われたのか！？`,ENG:`They took the reactor?`,TWN:`可惡！反應爐被搶走了嗎？！`},stage:{bg:`PROLOGUE_04`,slots:{L:{char_id:`JAKE_DELTA_PLAIN_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_SURPRISE`}}}},{id:`L10_1`,type:`dialog`,speaker:`JAKE_DELTA_PLAIN_NULL`,text:{KOREA:`순순히 넘겨 줄 수는…… 없지!`,JPN:`そんな簡単に渡すわけには……いかない！`,ENG:`I can’t just let them get away with it!`,TWN:`怎麼可以這麼簡單……就被他們搶走！`},stage:{bg:`PROLOGUE_04`,slots:{L:{char_id:`JAKE_DELTA_PLAIN_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_SURPRISE`}}}},{id:`L13_1`,type:`dialog`,speaker:`JAKE_DELTA_PLAIN_NULL`,text:{KOREA:`크윽?!`,JPN:`くうっ！？`,ENG:`Huh?!`,TWN:`唔？！`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`JAKE_DELTA_PLAIN_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_AVOID`,text:{KOREA:`대령의 공격을 가볍게 막아냈어?`,JPN:`大佐の攻撃を軽く止めただと？`,ENG:`She repelled the Colonel’s attack easily?`,TWN:`竟然可以輕易擋下上校的攻擊？`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_SURPRISE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_AVOID`,text:{KOREA:`대체 저런 괴물들이 어디서 자꾸 나타나는 거야?!`,JPN:`いったいどこからあんな化け物が次々と現れるんだ！？`,ENG:`Where the hell do these monsters keep appearing?!`,TWN:`這些怪物到底都是從哪裡冒出來的啦！`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_QM`,text:{KOREA:`나의 임무는 여기까지. 그대들과 더 이상 싸울 이유는 없다, 이방인.`,JPN:`私の任務はここまでだ。お前たちとこれ以上戦う理由はない、異邦人よ。`,ENG:`My duty here is done. I have no reason to fight you, outsiders.`,TWN:`外邦人，我的任務已經完成，沒有理由再繼續和你們打下去。`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JAKE_DELTA_PLAIN_NULL`,text:{KOREA:`미안하지만 이 쪽은 아직 볼 일이 안 끝났어!`,JPN:`悪いが、こっちはまだ用事が済んでないんでね！`,ENG:`Well, sorry. I’m not done with you!`,TWN:`不好意思喔，但我們的任務還沒完成！`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`JAKE_DELTA_PLAIN_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JAKE_DELTA_PLAIN_NULL`,text:{KOREA:`자기 일만 끝내고 멋대로 도망치는 건 나쁜 일이라고, 아가씨!`,JPN:`自分の用事だけ済ませて勝手に逃げるのは悪いことだよ、お嬢ちゃん！`,ENG:`You can’t just run because you’re done here! That's bad!`,TWN:`小丫頭，自己的事情完成就逃走是不好的行為喔！`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`JAKE_DELTA_PLAIN_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_QM`,text:{KOREA:`그런가. 새로운 가르침에 감사한다.`,JPN:`そうなのか。新しい教えに感謝する。`,ENG:`I see. Thank you for another lesson.`,TWN:`是嗎？再次謝謝你的教導。`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_QM`,text:{KOREA:`하지만 나에겐 다음 임무가 있어 지체할 수 없다.`,JPN:`だが、私には次の任務があり、遅れることはできない。`,ENG:`But I have a job to do. I can’t stay here any longer.`,TWN:`不過我接下來還有其他任務，請恕我無法奉陪。`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_QM`,text:{KOREA:`사과는 그 이후에 하겠다.`,JPN:`謝罪はその後にさせてもらう。`,ENG:`I will apologize later.`,TWN:`之後再向你們致歉。`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_AVOID`,text:{KOREA:`천장이 무너진다! 이대로는 생매장 되어버릴 거야!`,JPN:`天井が崩れる！　このままじゃ生き埋めだ！`,ENG:`The ceiling is collapsing! We’ll be buried alive!`,TWN:`天花板要塌了！!我們要被活埋了啦！`},stage:{bg:`PROLOGUE_04`,slots:{L:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`JAKE_DELTA_PLAIN_NULL`,face:`UNIT_HATE`}}}},{id:`L28_1`,type:`dialog`,speaker:`JAKE_DELTA_PLAIN_NULL`,text:{KOREA:`이런, 젠장……!`,JPN:`……クソ！`,ENG:`Oh, drat!`,TWN:`該死……！`},stage:{bg:`PROLOGUE_04`,slots:{L:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`JAKE_DELTA_PLAIN_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};